module encoder_8to3_enable(
    input wire [7:0] in,
    input wire en,
    output reg [2:0] input_data
    );

always @(*) begin
    if (en) begin
        case(in)
            8'b00000001: input_data = 3'b000;
            8'b00000010: input_data = 3'b001;
            8'b00000100: input_data = 3'b010;
            8'b00001000: input_data = 3'b011;
            8'b00010000: input_data = 3'b100;
            8'b00100000: input_data = 3'b101;
            8'b01000000: input_data = 3'b110;
            8'b10000000: input_data = 3'b111;
            default: input_data = 3'b000;
        endcase
    end else begin
        input_data = 3'b000;
    end
end

endmodule
